import React, { useState } from 'react';
import './CaseStudy.css';

const CaseStudy = ({ project, onClose }) => {
  const [activeSection, setActiveSection] = useState('overview');

  const caseStudyContent = {
    "VERA Fashion Shopping App UI": {
      hero: "/cover page of plant.png",
      overview: "Modern e-commerce mobile application designed to enhance the shopping experience with intuitive user flow and engaging visual design. The app focuses on making fashion shopping seamless and enjoyable.",
      problem: "Users needed a more intuitive way to browse and purchase fashion items online, with better product discovery and checkout process.",
      process: [
        "User research and persona development",
        "Competitive analysis and market research", 
        "Information architecture and user flows",
        "Wireframing and low-fidelity prototypes",
        "High-fidelity UI design and iterations",
        "Usability testing and refinements"
      ],
      wireframes: [
        "/cover page of plant.png",
        "/cover page of plant.png"
      ],
      uiScreens: [
        "/cover page of plant.png",
        "/cover page of plant.png",
        "/cover page of plant.png"
      ],
      mockups: [
        "/cover page of plant.png",
        "/cover page of plant.png"
      ]
    },
    "Plant Shop Mobile App": {
      hero: "/cover page of plant.png",
      overview: "Clean and minimalist plant shopping experience with product discovery features. Designed to make plant shopping accessible and enjoyable for all users.",
      problem: "Plant enthusiasts needed a dedicated platform to discover and purchase plants with detailed care information.",
      process: [
        "Market research and user interviews",
        "User journey mapping",
        "Content strategy and information design",
        "Mobile-first responsive design",
        "Prototyping and user testing",
        "Final design and handoff"
      ],
      wireframes: [
        "/cover page of plant.png",
        "/cover page of plant.png"
      ],
      uiScreens: [
        "/cover page of plant.png",
        "/cover page of plant.png",
        "/cover page of plant.png"
      ],
      mockups: [
        "/cover page of plant.png",
        "/cover page of plant.png"
      ]
    },
    "Sofar Service Website UI": {
      hero: "/covr page.png",
      overview: "Professional service platform with streamlined user journey and modern aesthetics. Designed to simplify service discovery and booking processes.",
      problem: "Service providers needed a better way to showcase their services and manage client relationships online.",
      process: [
        "Stakeholder interviews and requirements gathering",
        "Service design and user flows",
        "Brand identity and visual design",
        "Responsive web design",
        "Interactive prototyping",
        "User testing and optimization"
      ],
      wireframes: [
        "/CS sneakr prt 1.png",
        "/CS sneakr prt 2.png"
      ],
      uiScreens: [
        "/CS sneakr prt 3.png",
        "/covr page.png",
        "/CS sneakr prt 1.png"
      ],
      mockups: [
        "/covr page.png",
        "/CS sneakr prt 2.png"
      ]
    },
    "Dashboard UI Concept": {
      hero: "/covr page.png",
      overview: "Data-driven dashboard with complex information architecture and visual hierarchy. Designed to make data analysis intuitive and efficient.",
      problem: "Users needed a better way to visualize and analyze complex data sets with improved information architecture.",
      process: [
        "Data analysis and user requirements",
        "Information architecture design",
        "Dashboard layout and wireframing",
        "Visual design and data visualization",
        "Interactive prototyping",
        "Usability testing and iterations"
      ],
      wireframes: [
        "/covr page.png",
        "/covr page.png"
      ],
      uiScreens: [
        "/covr page.png",
        "/covr page.png",
        "/covr page.png"
      ],
      mockups: [
        "/covr page.png",
        "/covr page.png"
      ]
    }
  };

  const content = caseStudyContent[project.title];

  if (!content) return null;

  return (
    <div className="case-study-overlay" onClick={onClose}>
      <div className="case-study-modal" onClick={(e) => e.stopPropagation()}>
        <div className="case-study-header">
          <button className="close-btn" onClick={onClose}>×</button>
          <h2>{project.title}</h2>
        </div>

        <div className="case-study-content">
          {/* Navigation */}
          <div className="case-study-nav">
            {['overview', 'problem', 'process', 'wireframes', 'uiScreens', 'mockups'].map((section) => (
              <button
                key={section}
                className={`nav-btn ${activeSection === section ? 'active' : ''}`}
                onClick={() => setActiveSection(section)}
              >
                {section.charAt(0).toUpperCase() + section.slice(1).replace(/([A-Z])/g, ' $1')}
              </button>
            ))}
          </div>

          {/* Hero Image */}
          <div className="hero-section">
            <img src={content.hero} alt={project.title} />
          </div>

          {/* Content Sections */}
          {activeSection === 'overview' && (
            <div className="content-section">
              <h3>Overview</h3>
              <p>{content.overview}</p>
            </div>
          )}

          {activeSection === 'problem' && (
            <div className="content-section">
              <h3>Problem</h3>
              <p>{content.problem}</p>
            </div>
          )}

          {activeSection === 'process' && (
            <div className="content-section">
              <h3>Process</h3>
              <ol>
                {content.process.map((step, index) => (
                  <li key={index}>{step}</li>
                ))}
              </ol>
            </div>
          )}

          {activeSection === 'wireframes' && (
            <div className="content-section">
              <h3>Wireframes</h3>
              <div className="image-gallery">
                {content.wireframes.map((image, index) => (
                  <div key={index} className="gallery-item">
                    <img src={image} alt={`Wireframe ${index + 1}`} />
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeSection === 'uiScreens' && (
            <div className="content-section">
              <h3>UI Screens</h3>
              <div className="image-gallery">
                {content.uiScreens.map((image, index) => (
                  <div key={index} className="gallery-item">
                    <img src={image} alt={`UI Screen ${index + 1}`} />
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeSection === 'mockups' && (
            <div className="content-section">
              <h3>Final Mockups</h3>
              <div className="image-gallery">
                {content.mockups.map((image, index) => (
                  <div key={index} className="gallery-item">
                    <img src={image} alt={`Mockup ${index + 1}`} />
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CaseStudy;
